class Account:
    _account_count = 0  # Class attribute to track the account count

    def __init__(self, account_number, balance):
        self.account_number = account_number
        self.balance = balance
        Account._account_count += 1

    def withdraw(self, amount):
        if self.balance >= amount:
            self.balance -= amount
        else:
            print("Insufficient funds")

    @classmethod
    def get_account_count(cls):
        return cls._account_count

# Do not modify the code below. This function will be called during testing.
def default_test():
    account = Account(account_number=12345, balance=1000.0)
    account.withdraw(500.0)
    print(account.balance)
    print(Account.get_account_count())
